// Auto-generated — do not edit manually.
// Bot XMLs are encoded and domain-locked.

const ALLOWED_ORIGINS: string[] = [
  'localhost',
  '127.0.0.1',
  // Add your deployed domain here, e.g. 'frostydbot.replit.app'
];

export function isAllowedDomain(): boolean {
  const h = window.location.hostname;
  return ALLOWED_ORIGINS.some(d => h === d || h.endsWith('.' + d)) ||
         h.endsWith('.replit.dev') || h.endsWith('.replit.app');
}

const BOT_DATA: Record<string, string> = {
  '1': '',
  '2a': '',
  '2b': '',
  '2c': '',
  '4': '',
  '5': '',
  '5b': '',
  '5c': '',
  '7': '',
  '7b': '',
  '10': '',
  '11': '',
};

export function getBotXML(id: string): string | null {
  if (!isAllowedDomain()) return null;
  const encoded = BOT_DATA[id];
  if (!encoded) return null;
  const xml = atob(encoded);
  const watermark = '<!-- FrostyDBot © frostydbot.replit.app | Locked to official site only -->';
  return xml.replace(/^(<\?xml[^>]*>\s*)?/, match => match + watermark + '\n');
}